INSERT OR IGNORE INTO projects (id, slug, date, title, subtitle, description, image, facebook, sort_order)
VALUES ('project-1', 'belturbet-bounce-back', '6 November 2025', 'Belturbet - ''Bounce Back'' Youth Project', 'Rejuvenating an outdoor area by a waterfront', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"The young people at Bounce Back Youth Club in Belturbet took on the challenge of rejuvenating their outdoor area by the waterfront — and delivered outstanding results.\n\nWith guidance and support from Let''s Give Back, the group worked together to clean, repair, and refresh the space, creating a welcoming spot for the wider community to enjoy. Their teamwork, creativity, and pride in giving something back were genuinely inspiring to witness.\n\nA special thank-you went to Peter Cunningham and the team at Newtricity Clones, Monaghan, who donated the recycled timber used to build the new furniture. Their contribution made a real and visible difference to the finished space.\n\nThe project was made possible through funding from the CMETB, without whose support initiatives like this simply would not get off the ground.\n\n*Together we''re Building Skills, Building Community.*"}]}]}', 'https://media.letsgiveback.ie/projects/round-bench.jpg', 'https://www.facebook.com/permalink.php?story_fbid=122156192720785276&id=61573558281380&ref=embed_post', 0);

INSERT OR IGNORE INTO projects (id, slug, date, title, subtitle, description, image, facebook, sort_order)
VALUES ('project-2', 'food-truck-renovation', '7 November 2025', 'Food Truck Renovation', 'Preparing our community food truck', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"In November 2025, the Let''s Give Back community food truck entered Phase 1 of its renovation. This first stage focused on stripping, cleaning, and preparing the interior for a full fit-out, with the goal of turning it into a mobile coffee and food unit.\n\nOnce completed, the truck was intended to help fundraise for local projects, engage young people in hands-on learning, and bring communities together through events and pop-ups.\n\nA sincere thank-you was owed to SICAP at Monaghan Integrated Development for providing the start-up grant that allowed the project to begin. Their support made the first phase possible and moved the idea significantly closer to becoming a working community resource.\n\nPhase 2 brought the project to life. Appliances were installed, the final touches were completed, and the truck was wrapped in full Let''s Give Back style. The build was carried out with real care and professionalism — Eamon Treanor Engineering handled the construction work throughout, and Marc McMeel delivered clean, tidy electrical work from start to finish.\n\nThe truck was never just about food. It was about funding youth projects, creating opportunities, and building skills while building community.\n\n*The hatch opened — and the work continued.*"}]}]}', 'https://media.letsgiveback.ie/projects/food-truck.jpg', 'https://www.facebook.com/permalink.php?story_fbid=122170466324785276&id=61573558281380&ref=embed_post', 1);

INSERT OR IGNORE INTO projects (id, slug, date, title, subtitle, description, image, facebook, sort_order)
VALUES ('project-3', 'outdoor-space-at-breifne-college', '16 November 2025', 'Outdoor Space at Breifne College', 'Transforming an unused outdoor area into a practical and welcoming space for a school', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Over several weeks, Let''s Give Back worked alongside students and teachers from Breifne College to transform an unused outdoor area into a practical and welcoming space for the school.\n\nStudents were involved at every stage of the process. They helped prepare the ground, move and level stone, learn how to use tools safely, and build the main features of the space with guidance from staff and the Let''s Give Back team.\n\n**Phase One included:**\n\n- Ground preparation\n- Laying and levelling a stone surface\n- Building four raised garden beds\n- Constructing handmade benches\n- Creating a clean and safe foundation for the next stage\n\nThe phase was completed through strong teamwork and gave students the opportunity to develop practical skills and confidence while working together toward a shared goal.\n\nThanks were extended to the students of Breifne College for their hard work, to CMETB for funding support, to the Cavan School Completion Programme for their organisation and involvement, and to the staff of Breifne College for their support throughout.\n\nPhase Two focused on developing the centre area into a games and activity space for the school."}]}]}', 'https://media.letsgiveback.ie/projects/benches.jpg', 'https://www.facebook.com/permalink.php?story_fbid=122157391004785276&id=61573558281380&ref=embed_post', 2);

INSERT OR IGNORE INTO projects (id, slug, date, title, subtitle, description, image, facebook, sort_order)
VALUES ('project-4', 'canopy-bench-raffle', '7 February 2026', 'Canopy Bench Raffle', 'Handmade canopy bench raffle to support community projects', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"In early 2026, Let''s Give Back ran a raffle to support its social mission and community projects. The prize was a handmade canopy bench, constructed as part of a youth-led initiative. Entries were priced at €2 each, or €10 for ten, and participants entered by engaging with the post on Facebook and sending a Revolut payment with their name and number.\n\nThe winner was announced live on Facebook on 4 February 2026. Funds raised went directly towards supporting a group of young people in transforming an overgrown outdoor area into a recreational and gaming space. The project included a football pool, retro arcade-style games, and a range of skill, accuracy, balance, and coordination activities — building on the foundations laid during Phase 1, which had been supported by Breifne College, the Cavan School Completion Programme, and Alan Ryan, Creative Youth Coordinator at CMETB.\n\nStephanie and the team at Ardaghey Childcare Centre were the lucky winners of the canopy picnic bench. Delivering it was a pleasure. It was already in use when it arrived, with smiles all around. The bench became more than timber and screws — it provided a space for children to sit, talk, eat, learn, and make lasting memories.\n\nEvery ticket sold, every share, and every word of support went directly into building projects that benefit the community while giving young people real-world skills."}]}]}', 'https://media.letsgiveback.ie/projects/picnic-bench.jpg', 'https://www.facebook.com/permalink.php?story_fbid=122168126774785276&id=61573558281380&ref=embed_post', 3);

INSERT OR IGNORE INTO projects (id, slug, date, title, subtitle, description, image, facebook, sort_order)
VALUES ('project-5', 'learning-simple-diy-tasks', '5 March 2026', 'Learning simple DIY tasks', 'Guided involvement can turn everyday tasks into meaningful learning experiences', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"A recent Let''s Give Back project involved a series of small home tasks — putting up curtain poles, shelving, and a TV wall mount. What made the experience meaningful was that the young man involved did most of the work himself.\n\nRather than simply completing the jobs, the focus was on showing him how to measure, drill, and fix each item properly. Those few straightforward DIY tasks became an opportunity for him to build practical skills and genuine confidence. Not every young person gets the chance to work through something like this hands-on, with someone alongside them to guide rather than take over.\n\nThe goal was never just to finish the job. It was about teaching skills, building confidence, and showing young people that they were capable of doing things themselves.\n\nFor anyone with small jobs around the house — hanging blinds or curtains, putting up shelves, mounting a TV, or minor fixes — this kind of guided involvement can turn an ordinary afternoon into a meaningful learning experience."}]}]}', 'https://media.letsgiveback.ie/projects/drilling.jpg', 'https://www.facebook.com/permalink.php?story_fbid=122171470316785276&id=61573558281380&ref=embed_post', 4);

INSERT OR IGNORE INTO projects (id, slug, date, title, subtitle, description, image, facebook, sort_order)
VALUES ('project-6', 'commercial-truck-transformation', '8 November 2025', 'Commercial Truck Transformation', 'Handmade canopy bench raffle to support community projects', '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Work began on converting a former commercial delivery truck into a dual-purpose community vehicle, and it took shape quickly from the outset.\n\nThe old wrapping was removed, the bodywork cleaned down, and the truck was prepared for its new design and purpose. Large enough to tow the Let''s Give Back food truck, it added a new level of flexibility for future community events and projects.\n\nOne side was fitted out for tool and materials storage to support community builds, while the other incorporated refrigerated space for food outreach and events. Existing shelving was reused throughout to limit material usage and reduce waste.\n\nThe project brought together upcycling, sustainability, and purpose — taking something once retired and turning it into something that gives back.\n\n*Building Skills, Building Community.*"}]}]}', 'https://media.letsgiveback.ie/projects/truck-interior.jpg', 'https://www.facebook.com/permalink.php?story_fbid=122156426654785276&id=61573558281380&ref=embed_post', 5);